### 5. Refactored Route Handlers

The route files become thin HTTP adapters. Here is the structural pattern for each.

**`src/routes/products.ts` (refactored):**

```typescript
import { Router } from "express";
import { getProducts, getProductById, adjustProductStock } from "../services/product-service.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;
  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" ? parseFloat(minPrice) : undefined,
    maxPrice: typeof maxPrice === "string" ? parseFloat(maxPrice) : undefined,
  };
  // Clean up NaN values
  if (filters.minPrice !== undefined && isNaN(filters.minPrice)) filters.minPrice = undefined;
  if (filters.maxPrice !== undefined && isNaN(filters.maxPrice)) filters.maxPrice = undefined;

  const result = getProducts(filters);
  res.json(result);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getProductById(id);
  if (!result.success) {
    res.status(result.code === "NOT_FOUND" ? 404 : 400).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };
  const result = adjustProductStock(id, adjustment);
  if (!result.success) {
    res.status(result.code === "NOT_FOUND" ? 404 : 400).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

export { router as productRouter };
```

**`src/routes/orders.ts` (refactored):**

```typescript
import { Router } from "express";
import { getOrders, getOrderById, createOrder, updateOrderStatus } from "../services/order-service.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;
  const filters = {
    userId: typeof userId === "string" ? parseInt(userId, 10) : undefined,
    status: typeof status === "string" ? status : undefined,
  };
  if (filters.userId !== undefined && isNaN(filters.userId)) filters.userId = undefined;

  const result = getOrders(filters);
  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getOrderById(id);
  if (!result.success) {
    res.status(404).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;
  const result = createOrder(input);
  if (!result.success) {
    res.status(400).json({ error: result.error });
    return;
  }
  res.status(201).json(result.data);
});

