import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderSummary {
  count: number;
  totalRevenue: number;
}

export interface OrderListResult {
  orders: Order[];
  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export type ServiceResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: string; status: number };

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): ServiceResult<EnrichedOrder> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { ok: false, error: "Order not found", status: 404 };
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ok: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return { ok: false, error: "userId and items are required", status: 400 };
  }

  if (input.items.length === 0) {
    return {
      ok: false,
      error: "Order must have at least one item",
      status: 400,
    };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return {
        ok: false,
        error: `Product ${item.productId} not found`,
        status: 400,
      };
    }

    if (item.quantity <= 0) {
      return { ok: false, error: "Quantity must be positive", status: 400 };
    }

    if (product.stock < item.quantity) {
      return {
        ok: false,
        error: `Insufficient stock for ${product.name}`,
        status: 400,
      };
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { ok: true, data: order };
}

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { ok: false, error: "Order not found", status: 404 };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    return {
      ok: false,
      error: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      status: 400,
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      ok: false,
      error: `Cannot transition from ${order.status} to ${status}`,
      status: 400,
    };
  }

  order.status = status as typeof order.status;

  return { ok: true, data: order };
}

